// Middleware: ensure user can only access their own resources
function ownershipCheck(resourceType: string) {
  return async (req: Request, res: Response, next: NextFunction) => {
    const resourceId = parseInt(req.params.id);
    const userId = req.user.id;

    let resource;
    switch (resourceType) {
      case 'post':
        resource = await prisma.post.findUnique({ where: { id: resourceId } });
        if (resource?.authorId !== userId && req.user.role !== 'ADMIN') {
          return res.status(403).json({ error: 'Access denied' });
        }
        break;
    }

    next();
  };
}

// Usage
router.put('/posts/:id', authMiddleware, ownershipCheck('post'), updatePostHandler);
router.delete('/posts/:id', authMiddleware, ownershipCheck('post'), deletePostHandler);
